 1	import { type Dispatch, type FC, type FormEvent, type SetStateAction, useState } from 'react';
 2	import { validateNoSpaces } from 'src/modules/Providers/utils/validators/common';
 3	
 4	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
 5	import { Button, ButtonVariant, InputGroup, TextInput } from '@patternfly/react-core';
 6	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 7	import { useForkliftTranslation } from '@utils/i18n';
 8	import { ValidationState } from '@utils/validation/Validation';
 9	
10	type HostsNetworksSetPasswordProps = {
11	  password: string;
12	  setPassword: Dispatch<SetStateAction<string>>;
13	};
14	
15	const HostsNetworksSetPassword: FC<HostsNetworksSetPasswordProps> = ({ password, setPassword }) => {
16	  const { t } = useForkliftTranslation();
17	
18	  const [passwordValidation, setPasswordValidation] = useState<ValidationState>(
19	    ValidationState.Default,
20	  );
21	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
22	
23	  const onChangePassword: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
24	    _event,
25	    value,
26	  ) => {
27	    const isValidPassword = validateNoSpaces(value);
28	    setPasswordValidation(isValidPassword ? ValidationState.Success : ValidationState.Error);
29	    setPassword(value);
30	  };
31	
32	  const togglePasswordHidden = () => {
33	    setPasswordHidden((isHidden) => !isHidden);
34	  };
35	
36	  return (
37	    <FormGroupWithHelpText
38	      label={t('ESXi host admin password')}
39	      isRequired
40	      fieldId="password"
41	      helperText={t('The password for the ESXi host admin')}
42	      helperTextInvalid={t('Invalid password')}
43	      validated={passwordValidation}
44	    >
45	      <InputGroup>
46	        <TextInput
47	          spellCheck="false"
48	          className="forklift-host-modal-input-secret"
49	          isRequired
50	          type={passwordHidden ? 'password' : 'text'}
51	          aria-label="Password input"
52	          value={password}
53	          onChange={onChangePassword}
54	          validated={passwordValidation}
55	        />
56	        <Button variant={ButtonVariant.control} onClick={togglePasswordHidden}>
57	          {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
58	        </Button>
59	      </InputGroup>
60	    </FormGroupWithHelpText>
61	  );
62	};
63	
64	export default HostsNetworksSetPassword;

